#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <cstdio>

int main() {
    int fd[2]; // tableau de 2 entiers pour les descripteurs de fichier
    pipe(fd); // crée un pipe

    pid_t pid = fork(); // crée un nouveau processus

    if (pid == -1) {
        std::cerr << "Erreur lors de la création du processus" << std::endl;
        return 1;
    } else if (pid == 0) { // dans le processus enfant
        close(fd[1]); // ferme l'écriture du pipe
        dup2(fd[0], STDIN_FILENO); // remplace l'entrée standard par le descripteur de lecture du pipe
        close(fd[0]); // ferme le descripteur de lecture du pipe (plus nécessaire)
        execlp("your-command", "your-command", (char*)0); // exécute le programme
        std::cerr << "Erreur lors de l'exécution du programme" << std::endl;
        return 1;
    } else { // dans le processus parent
        close(fd[0]); // ferme la lecture du pipe
        // Utilise fd[1] pour écrire dans le processus enfant
        std::cout << "Message pour le processus enfant" << std::endl;
        std::cout.flush();
        wait(NULL); // attend que le processus enfant termine
        return 0;
    }
}
```

